mapper.insert:
INSERT INTO product(
        pno
        , pClassification
        , pName
        , pPrice
        , pRegDate
        , firstThumbnail
        )
    VALUES(
        #{pno}
        , #{pClassification}
        , #{pName}
        , #{pPrice}
        , sysdate
        , #{firstThumbnail}
    )

INSERT INTO productOp(
    pOpNo
    , pno
    , pSize
    , pColor
    , pStock
)
VALUES(
    #{pOpNo}
    , #{pno}
    , #{pSize}
    , #{pColor}
    , #{pStock}
)
